CREATE TABLE DESCONTO_PROGRESSIVO (
VA_PERC_INICIAL_ENTRADA         DOUBLE PRECISION NOT NULL,
VA_PERC_FINAL_ENTRADA		DOUBLE PRECISION NOT NULL,
VA_PERC_DESCONTO		DOUBLE PRECISION DEFAULT 0);
ALTER TABLE DESCONTO_PROGRESSIVO ADD PRIMARY KEY (VA_PERC_INICIAL_ENTRADA,VA_PERC_FINAL_ENTRADA);
CREATE TABLE MORA_PROGRESSIVA (
  CO_STATUS_CTR                 CHAR(1) DEFAULT 'T' NOT NULL,
  VA_PERC_INICIAL_ENTRADA       DOUBLE PRECISION NOT NULL,
  VA_PERC_FINAL_ENTRADA		DOUBLE PRECISION NOT NULL,
  VA_DEBITO_INICIAL             DOUBLE PRECISION NOT NULL,
  VA_DEBITO_FINAL               DOUBLE PRECISION NOT NULL,
  VA_PERC_ISENMORA              DOUBLE PRECISION DEFAULT 0);
ALTER TABLE MORA_PROGRESSIVA ADD PRIMARY KEY (CO_STATUS_CTR,VA_PERC_INICIAL_ENTRADA,VA_PERC_FINAL_ENTRADA,VA_DEBITO_INICIAL,VA_DEBITO_FINAL);
CREATE TABLE ACAO (	
       NOME                 VARCHAR(50) NOT NULL,
       DESCRICAO            VARCHAR(100),
       ACAO                 VARCHAR(150),
       CODFUNCAO            INTEGER,
       NO_HELP              VARCHAR(255),
       IN_DISPONIVEL_USUARIO CHAR(1) DEFAULT 'f');
CREATE INDEX XIF122ACAO ON ACAO(
       CODFUNCAO);
ALTER TABLE ACAO ADD CONSTRAINT XPKACAO PRIMARY KEY (NOME);
