CREATE TABLE AMBIENTECONTEXTO (
       CONTEXTO             VARCHAR(22) NOT NULL,
       VARIAVEL             VARCHAR(20) NOT NULL,
       VALOR                VARCHAR(120));
ALTER TABLE AMBIENTECONTEXTO ADD CONSTRAINT XPKAMBIENTECONTEXTO PRIMARY KEY (CONTEXTO, VARIAVEL);
CREATE TABLE ITEMDEMENU (
	CONTEXTO	VARCHAR(22) NOT NULL,
        MENU		VARCHAR(20) NOT NULL,
	CAMINHO		VARCHAR(150) NOT NULL,
	NOMEACAO	VARCHAR(50),
	IMAGEM		VARCHAR(20),
	ORDEM			INTEGER);
ALTER TABLE ITEMDEMENU ADD PRIMARY KEY (CONTEXTO,MENU,CAMINHO);
ALTER TABLE ITEMDEMENU ADD CONSTRAINT R_FK_ITEMDEMENU_ACAO FOREIGN KEY (NOMEACAO) REFERENCES ACAO;
CREATE INDEX R_FK_ITEMDEMENU_ACAO ON ITEMDEMENU(NOMEACAO);
CREATE TABLE TIPO_DOC_DOSSIE (
  CO_DOC_DOSSIE       INTEGER NOT NULL,
  NO_DOCUMENTACAO     VARCHAR(255));
ALTER TABLE TIPO_DOC_DOSSIE ADD PRIMARY KEY (CO_DOC_DOSSIE);
CREATE TABLE SISTARQ (
       ID                   INTEGER NOT NULL,
       IDPAI                INTEGER NOT NULL,
       NOME                 VARCHAR(250),
       TIPO                 INTEGER,
       NU_COPIAS            INTEGER,
       IN_CONTROLE_VERSAO   CHAR(1) DEFAULT 'N',
       IN_CRIA_VERSAO_ATUALIZADA CHAR(1) DEFAULT 'S',
       IN_DOCUMENTO_OCULTO  CHAR(1) DEFAULT 'N',
       IN_DOCUMENTO_SO_LEITURA CHAR(1) DEFAULT 'N',
       TE_OBSERVACAO_ARQUIVO BYTEA,
       NO_DESCRICAO         VARCHAR(255),
       CO_DOC_DOSSIE        INTEGER,
       CO_HIERARQUIA_DOCUMENTO INTEGER,
       IN_EXIBE_PASTA  CHAR(1) DEFAULT 'N',
       NU_ORDEM             INTEGER,
       IDRAIZ               INTEGER,
       CO_TIPO_ARQUIVO      INTEGER DEFAULT 0,
       CO_IDENTIFICACAO     INTEGER DEFAULT 0,
       IN_CONTROLE_ASSINATURA  CHAR(1) DEFAULT 'F',
       IN_TIPO_ASSINATURA      INTEGER DEFAULT 0,
       QT_REPRESENTANTES_ASSIN INTEGER DEFAULT 0);
ALTER TABLE SISTARQ ADD PRIMARY KEY (ID);
ALTER TABLE SISTARQ ADD CONSTRAINT R_FK_SISTARQ FOREIGN KEY (IDPAI) REFERENCES SISTARQ;
CREATE INDEX R_FK_SISTARQ ON SISTARQ(IDPAI);
ALTER TABLE SISTARQ ADD CONSTRAINT R_FK_SISTARQ_TIPO FOREIGN KEY (CO_DOC_DOSSIE) REFERENCES TIPO_DOC_DOSSIE;
CREATE INDEX R_FK_SISTARQ_TIPO ON SISTARQ(CO_DOC_DOSSIE);
ALTER TABLE SISTARQ ADD CONSTRAINT R_FK_SISTARQ2 FOREIGN KEY (CO_HIERARQUIA_DOCUMENTO) REFERENCES SISTARQ;
CREATE INDEX R_FK_SISTARQ2 ON SISTARQ(CO_HIERARQUIA_DOCUMENTO);
CREATE UNIQUE INDEX XAK1SISTARQ ON SISTARQ(IDPAI,NOME);
CREATE INDEX XAK2SISTARQ ON SISTARQ(IDRAIZ,NOME);
CREATE TABLE PERFIL_SISTARQ (
  COD_PERFIL               INTEGER,
  ID                       INTEGER NOT NULL,
  NU_PERFIL_SISTARQ	   INTEGER NOT NULL,
  COD_ENT	           INTEGER,
  CO_SETOR	           VARCHAR(5),
  USUARIO	           VARCHAR(20),
  IN_PODE_ATUALIZAR	   CHAR(1) DEFAULT 'F',
  IN_PODE_EXCLUIR	   CHAR(1) DEFAULT 'F');
ALTER TABLE PERFIL_SISTARQ ADD CONSTRAINT XPK_PERFIL_SISTARQ PRIMARY KEY (NU_PERFIL_SISTARQ, ID);
CREATE INDEX XIK_PERFIL_SISTARQ ON PERFIL_SISTARQ(ID);
ALTER TABLE PERFIL_SISTARQ ADD CONSTRAINT XFK1_PERFIL_SISTARQ FOREIGN KEY (COD_PERFIL) REFERENCES PERFIL ON DELETE CASCADE;
CREATE INDEX XFK1_PERFIL_SISTARQ ON PERFIL_SISTARQ(COD_PERFIL);
ALTER TABLE PERFIL_SISTARQ ADD CONSTRAINT XFK2_PERFIL_SISTARQ FOREIGN KEY (ID) REFERENCES SISTARQ ON DELETE CASCADE;
CREATE INDEX XFK2_PERFIL_SISTARQ ON PERFIL_SISTARQ(ID);
CREATE SEQUENCE SQ_GEN_NU_PERFIL_SISTARQ;
CREATE TABLE CONTROLEVERSAO (
       ID                   INTEGER NOT NULL,
       VERSAO               INTEGER NOT NULL,
       DADO                 BYTEA,
       ALT_USUARIO          VARCHAR(20),
       ALT_DATA             TIMESTAMP,
       CO_USUARIO_IMPLANTACAO VARCHAR(20),
       DT_IMPLANTACAO_VERSAO TIMESTAMP,
       TE_OBSERVACAO_VERSAO BYTEA,
       COMPACTADO           CHAR(1),
       TP_GRAVACAO          SMALLINT,
       NOME                 VARCHAR(250),
       NU_TAMANHO_ARQUIVO   INTEGER,
       NU_TAMANHO_COMPACTADO INTEGER,
       TE_IMAGEM_REDUZIDA BYTEA,
       HASH_DOCUMENTO_MIGRADO VARCHAR(100));
ALTER TABLE CONTROLEVERSAO ADD PRIMARY KEY (VERSAO, ID);
ALTER TABLE CONTROLEVERSAO ADD CONSTRAINT R_CONTROLEVERSAO_SISTARQ FOREIGN KEY (ID) REFERENCES SISTARQ ON DELETE CASCADE;
CREATE INDEX R_CONTROLEVERSAO_SISTARQ ON CONTROLEVERSAO(ID);
CREATE INDEX AKCONTROLEVERSAOUSUARIO ON CONTROLEVERSAO( CO_USUARIO_IMPLANTACAO );
CREATE INDEX CONTROLEVERSAODATA ON CONTROLEVERSAO(ALT_DATA,ID);



CREATE SEQUENCE SQ_ID_SISTARQ;
