CREATE TABLE CADIMV_IB (
       CO_EMPREEND          INTEGER NOT NULL,
       CO_IMOVEL            VARCHAR(10) NOT NULL,
       NO_DESC_LIVRE_IMV    BYTEA,
       TE_RESTRICOES_AO_IMOVEL BYTEA,
       TE_SITUACAO_IMOVEL  BYTEA);
CREATE INDEX XIF151CADIMV_IB ON CADIMV_IB(
       CO_EMPREEND);
ALTER TABLE CADIMV_IB ADD CONSTRAINT XPKCADIMV_IB PRIMARY KEY (CO_IMOVEL, CO_EMPREEND);
CREATE TABLE ATENDIMENTO_FGTS (
       NU_ATENDIMENTO       INTEGER NOT NULL,
       CO_SERVICO           CHAR(2) NOT NULL,
       CO_USUARIO_ATENDIMENTO VARCHAR(20),
       CO_REGIONAL          VARCHAR(5),
       CO_TIPO_SERVICO      CHAR(2) NOT NULL,
       NU_CONTRATO_SCCI     CHAR(17),
       NU_CONJUNTO          CHAR(4),
       CO_CARTEIRA          CHAR(3),
       DT_ASSINATURA_DAMP   TIMESTAMP,
       DT_CALCULO_DAMP3     TIMESTAMP,
       VA_FGTS_DISPONIVEL   DOUBLE PRECISION,
       QT_PRESTACOES_VENCIDAS INTEGER,
       VA_PRESTACOES_VENCIDAS DOUBLE PRECISION,
       QT_PRESTACOES_QUITAR_FGTS INTEGER,
       VA_PRESTACOES_QUITAR_FGTS DOUBLE PRECISION,
       QT_PRESTACOES_QUITAR_MUTUARIO INTEGER,
       VA_PRESTACOES_QUITAR_MUTUARIO DOUBLE PRECISION,
       VA_SALDO_DEVEDOR     DOUBLE PRECISION,
       QT_PRESTACOES_REMANESCENTES INTEGER,
       DT_BAIXA_SCCI        TIMESTAMP);
CREATE INDEX XIF155ATENDIMENTO_FGTS ON ATENDIMENTO_FGTS(
       CO_USUARIO_ATENDIMENTO);
ALTER TABLE ATENDIMENTO_FGTS ADD CONSTRAINT XPKATENDIMENTO_FGTS PRIMARY KEY (NU_ATENDIMENTO);
CREATE TABLE PESSOA_FGTS (
       NU_ATENDIMENTO       INTEGER NOT NULL,
       NU_PESSOA_ATENDIMENTO INTEGER NOT NULL,
       NO_EMPRESA           VARCHAR(40),
       NU_CGC_EMPRESA       VARCHAR(14),
       NU_CTPS              VARCHAR(10),
       NU_SERIE_CTPS        VARCHAR(5),
       NU_BANCO_FGTS        CHAR(20),
       NU_CONTA_FGTS        VARCHAR(20),
       VA_UTILIZADO_FGTS    DOUBLE PRECISION,
       NO_ENDERECO_EMPRESA  VARCHAR(40),
       DT_NASCIMENTO        TIMESTAMP,
       NO_ENDERECO          VARCHAR(40),
       NO_BAIRRO            VARCHAR(20),
       NU_MUNICIPIO         CHAR(5),
       CO_UF                CHAR(2),
       NU_CEP               VARCHAR(10),
       NU_DDD               CHAR(4),
       NU_TELEFONE          VARCHAR(14),
       NU_IDENTIDADE        VARCHAR(15),
       CO_ORGAO_EMISSOR_IDENTIDADE VARCHAR(10),
       NO_NACIONALIDADE     VARCHAR(20),
       IN_ESTADO_CIVIL      CHAR(1),
       NO_PESSOA            VARCHAR(40),
       NU_CPF               VARCHAR(14),
       NO_PROFISSAO         VARCHAR(40),
       NU_PISPASEP          VARCHAR(15));
CREATE INDEX XIF153PESSOA_FGTS ON PESSOA_FGTS(
       NU_ATENDIMENTO);
ALTER TABLE PESSOA_FGTS ADD CONSTRAINT XPKPESSOA_FGTS PRIMARY KEY (NU_ATENDIMENTO,
              NU_PESSOA_ATENDIMENTO);
ALTER TABLE ATENDIMENTO_FGTS ADD CONSTRAINT R_155
              FOREIGN KEY (CO_USUARIO_ATENDIMENTO)
                             REFERENCES USUARIO;
CREATE INDEX R_155 ON ATENDIMENTO_FGTS(CO_USUARIO_ATENDIMENTO);
ALTER TABLE PESSOA_FGTS ADD CONSTRAINT R_122
              FOREIGN KEY (NU_ATENDIMENTO)
                             REFERENCES ATENDIMENTO_FGTS;
CREATE INDEX R_122 ON PESSOA_FGTS(NU_ATENDIMENTO);
CREATE TABLE CONFIGURACAO (
        NU_SEQ               INTEGER NOT NULL,
        IN_EDITA_COM_WORD    CHAR(1) DEFAULT 'N',
        NO_AGENTE            VARCHAR(40),
        NO_ENDERECO_AGENTE   VARCHAR(40),
        NO_MINICIPIO_AGENTE  VARCHAR(20),
        CO_UF_AGENTE         CHAR(2),
        NU_COTA              SMALLINT,
        NU_CERCEF_PADRAO     VARCHAR(20),
        NO_GERENTE_DEPARTAMENTO VARCHAR(40),
        NO_CARGO_GERENTE_DEPARTAMENTO VARCHAR(40),
        NU_CPF_GERENTE_DEPARTAMENTO CHAR(11),
        ID_CIP_DOCUMENTO_ORIGINAL  INTEGER,
        ID_CIP_PADRAO_IMOVEL       INTEGER,
        ID_CIP_PADRAO_PROJETO      INTEGER,
        ID_CIP_DOCUMENTO_MERGEADO  INTEGER,
        IN_SISAT_FILTRO_GESTOR CHAR(1) DEFAULT 'N',
        CO_SISAT_ENTIDADE_COBRANCA INTEGER,
        CO_SISAT_TAREFA_COBRANCA CHAR(3),
        NU_SISAT_MUNICIPIO_COBRANCA INTEGER DEFAULT 0,
        IN_SISAT_TIPO_COBRANCA  CHAR(1),
        IN_SISAT_ENVIA_EMAIL_TAREFA CHAR(1),
        IN_SISAT_COPIA_EXECUCAO CHAR(1) DEFAULT 'N',
        CO_SISAT_TAREFA_FINALIZADO CHAR(3),
