CREATE TABLE RESP_CEF_RNV (
	CO_RESP_CEF		INTEGER NOT NULL,
  	DESCRICAO		VARCHAR(20) NOT NULL);
ALTER TABLE RESP_CEF_RNV ADD CONSTRAINT XPKRESP_CEF_RNV PRIMARY KEY (CO_RESP_CEF);
CREATE TABLE RESP_AGENTE_RNV (
	CO_RESP_AGENTE        	INTEGER NOT NULL,
  	DESCRICAO		VARCHAR(20) NOT NULL);
ALTER TABLE RESP_AGENTE_RNV ADD CONSTRAINT XPKRESP_AGENTE_RNV PRIMARY KEY (CO_RESP_AGENTE);
CREATE TABLE TRAMITE_RNV(
	CONTRATO		VARCHAR(7) NOT NULL,
  	NU_CORRESPONDENCIA      VARCHAR(20) NOT NULL,
        DT_ENVIO                TIMESTAMP,
        CO_RESP_AGENTE         INTEGER,
        DT_RESP_CEF             TIMESTAMP,
        CO_RESP_CEF            INTEGER,
        OBS                     BYTEA);
ALTER TABLE TRAMITE_RNV ADD CONSTRAINT XPKTRAMITE_RNV PRIMARY KEY (CONTRATO, NU_CORRESPONDENCIA);
ALTER TABLE TRAMITE_RNV ADD CONSTRAINT R_TRAMITE_RNV_RESP_CEF_RNV
              FOREIGN KEY (CO_RESP_CEF)
              REFERENCES RESP_CEF_RNV;
CREATE INDEX R_TRAMITE_RNV_RESP_CEF_RNV ON TRAMITE_RNV(CO_RESP_CEF);
ALTER TABLE TRAMITE_RNV ADD CONSTRAINT R_TRAMITE_RNV_RESP_AGENTE_RNV
              FOREIGN KEY (CO_RESP_AGENTE)
              REFERENCES RESP_AGENTE_RNV;
CREATE INDEX R_TRAMITE_RNV_RESP_AGENTE_RNV ON TRAMITE_RNV(CO_RESP_AGENTE);
CREATE TABLE LOG_EVENTOS(
       CO_LOG               INTEGER NOT NULL, 
       CO_APLIC             INTEGER NOT NULL,
       CO_SEVERIDADE        SMALLINT NOT NULL,
       NU_CONTRATO          VARCHAR(17),
       NO_USUARIO           VARCHAR(20),
       DT_DATA_HORA         TIMESTAMP NOT NULL,
       NO_MENSAGEM          VARCHAR(71),
       NO_COMPLEMENTO       VARCHAR(71),
       CO_DETALHE           INTEGER,
       DT_DATA_DETALHE      VARCHAR(14),
       TE_DADOS             BYTEA,
       NU_PRETENDENTE       VARCHAR(9),
       NO_TABELA            VARCHAR(40),
       NO_BASE              VARCHAR(15),
       CO_USUARIO_LEITURA   VARCHAR(20) DEFAULT '',
       DT_LEITURA           TIMESTAMP DEFAULT NULL,
       NO_USUARIO_ALTERADO  VARCHAR(20),
       CO_EMPRESA           INTEGER DEFAULT 0);
CREATE INDEX XIFLOG_EVENTOS_APLIC ON LOG_EVENTOS(CO_APLIC);
CREATE INDEX XIFLOG_EVENTOS_DETALHE ON LOG_EVENTOS(CO_APLIC,CO_DETALHE,DT_DATA_DETALHE);
CREATE INDEX XIFLOG_EVENTOS_IXD ON LOG_EVENTOS(CO_APLIC,DT_DATA_HORA);
CREATE INDEX XIFLOG_EVENTOS_IXDDB ON LOG_EVENTOS(NU_CONTRATO,DT_DATA_HORA);
CREATE INDEX XIFLOG_EVENTOS_PRETDATA ON LOG_EVENTOS(NU_PRETENDENTE,DT_DATA_HORA);
CREATE INDEX XIFLOG_EVENTOS_TABDATA ON LOG_EVENTOS(NO_TABELA,DT_DATA_HORA);
CREATE INDEX XIFLOG_EVENTOS_BASEDATA ON LOG_EVENTOS(NO_BASE,DT_DATA_HORA);
CREATE INDEX XIFLOG_EVENTOS_DATAHORA on log_eventos (dt_data_hora DESC);
CREATE INDEX XIFLOG_EVENTOS_USUARIO ON LOG_EVENTOS(NO_USUARIO, CO_APLIC, DT_DATA_HORA);
CREATE INDEX XIF_LOG_EVENTOS_CONTRATO ON LOG_EVENTOS(NU_CONTRATO);
CREATE SEQUENCE SQ_GEN_LOG_EVENTOS;
CREATE TABLE EVENTOS (
        NU_EVENTO          INTEGER NOT NULL,
	NO_EVENTO          VARCHAR(31) NOT NULL,
  	NO_ACAO		   VARCHAR(30),
        TE_PARAMETROS      BYTEA,
        CO_EMPRESA         INTEGER DEFAULT 0);
CREATE INDEX XIFNO_EVENTO ON EVENTOS(
       NO_EVENTO);
ALTER TABLE EVENTOS ADD CONSTRAINT XPKNU_EVENTO PRIMARY KEY (NU_EVENTO);
CREATE SEQUENCE SQ_GEN_EVENTOS;
CREATE TABLE CONTROLE_RELATORIO_PROD(
       NU_SEQ        INTEGER DEFAULT 0 NOT NULL,
       CO_OPERACAO   INTEGER NOT NULL,
       DATA_OPERACAO TIMESTAMP NOT NULL,
       NU_EXEC       INTEGER NOT NULL,   
       NO_FISICO_REL VARCHAR(250),
       NU_TAM_FONTE INTEGER,
       CO_ANDAMENTO_FASE INTEGER);
ALTER TABLE CONTROLE_RELATORIO_PROD ADD CONSTRAINT XPKCONTROLE_RELATORIO_PROD PRIMARY KEY (NU_SEQ);
CREATE INDEX XIFCONTROLE_REL ON CONTROLE_RELATORIO_PROD(CO_OPERACAO,DATA_OPERACAO,NU_EXEC);
CREATE INDEX XIFCONTROLE_REL_ANDAMENTO ON CONTROLE_RELATORIO_PROD(CO_ANDAMENTO_FASE);
CREATE SEQUENCE SQ_GEN_CONTROLE_RELATORIO_PROD;
CREATE TABLE CAIXA (
       DT_ABERTURA          TIMESTAMP NOT NULL,
       NU_CAIXA             INTEGER NOT NULL,
       CO_USUARIO           VARCHAR(20),
       DT_FECHAMENTO        TIMESTAMP);
ALTER TABLE CAIXA ADD PRIMARY KEY (DT_ABERTURA, NU_CAIXA);
CREATE TABLE MOVIMENTO (
       DT_MOVIMENTO         TIMESTAMP NOT NULL,
       NU_CAIXA             INTEGER NOT NULL,
       TP_MOVIMENTO         INTEGER NOT NULL,
       NU_MOVIMENTO         INTEGER NOT NULL,
       NU_DOCUMENTO         VARCHAR(15) NOT NULL,
       NU_MAC               INTEGER NOT NULL,
       NU_MORA              FLOAT,
       TP_RECIBO            INTEGER,
       NU_TOTAL             FLOAT,
       CO_USUARIO           VARCHAR(20),
       NU_NOSSONUM          VARCHAR(15),
       CO_SERIE             INTEGER NOT NULL,
       TP_PARC              INTEGER NOT NULL);
ALTER TABLE MOVIMENTO ADD PRIMARY KEY (DT_MOVIMENTO, NU_CAIXA, NU_MOVIMENTO, NU_MAC, CO_SERIE,TP_PARC);
