CREATE TABLE CONTA_FGTS (
       NU_ATENDIMENTO       CHAR(8) NOT NULL,
       NU_PESSOA            CHAR(2) NOT NULL,
       NO_EMPRESA           VARCHAR(40),
       NU_CGC_EMPRESA       VARCHAR(14) NOT NULL,
       NU_BANCO_FGTS        VARCHAR(20) NOT NULL,
       NU_CONTA_FGTS        VARCHAR(20) NOT NULL,
       NO_ENDERECO_EMPRESA  VARCHAR(40),
       NU_CTPS              VARCHAR(10),
       NU_SERIE_CTPS        VARCHAR(5),
       VA_UTILIZADO_FGTS    DOUBLE PRECISION,
       CO_UF_EMPRESA        CHAR(2),
       NO_CIDADE_EMPRESA    VARCHAR(20),
       IN_TIPO_CONTA        CHAR(1),
       CO_UF_CONTA          CHAR(2));
ALTER TABLE CONTA_FGTS ADD CONSTRAINT XPKCONTA_FGTS PRIMARY KEY (
              NU_ATENDIMENTO, NU_PESSOA, NU_CGC_EMPRESA, NU_BANCO_FGTS,
              NU_CONTA_FGTS);
CREATE TABLE FGTS_ATENDIMENTO (
       NU_ATENDIMENTO       CHAR(8) NOT NULL,
       VA_RECURSO_PROPRIO   DOUBLE PRECISION,
       NO_TEMPO_RESIDENCIA_SEGURADO VARCHAR(20),
       NO_COMCUBINATO_SEGURADO VARCHAR(40),
       NO_NACIONALIDADE_COMCUBINATO VARCHAR(20),
       TE_FILHOS_SEGURADO  BYTEA,
       CO_TIPO_DAMP          CHAR(2),
       IN_FGTS_PARCIAL_TOTAL CHAR(1),
       NU_PRESTACOES_ABATER DOUBLE PRECISION,
       DT_INICIO_UTILIZACAO_FGTS TIMESTAMP,
       PE_ABATIMENTO_PRESTACAO DOUBLE PRECISION,
       PE_LIQUIDO_AMORTIZACAO_PREST DOUBLE PRECISION,
       VA_SALDO_DEVEDOR     DOUBLE PRECISION,
       VA_PRESTACAO_ATUAL   DOUBLE PRECISION,
       NU_AGENCIA_DEPOSITO  VARCHAR(5),
       NU_BANCO_DEPOSITO    CHAR(6),
       NU_CONTA_DEPOSITO    VARCHAR(20),
       DT_NASCIMENTO_SEGURADO TIMESTAMP,
       NO_ENDERECO_SEGURADO VARCHAR(40),
       NO_BAIRRO_SEGURADO   VARCHAR(20),
       NO_CIDADE_SEGURADO   VARCHAR(20),
       CO_UF_SEGURADO       CHAR(2),
       NU_CEP_SEGURADO      VARCHAR(10),
       NU_DDD_SEGURADO      CHAR(4),
       NU_TELEFONE_SEGURADO VARCHAR(14),
       NU_RG_SEGURADO       VARCHAR(11),
       CO_ORGAO_SEGURADO    VARCHAR(10),
       NO_NACIONALIDADE_SEGURADO VARCHAR(20),
       IN_ESTADO_CIVIL_SEGURADO CHAR(1),
       VA_SALBRUTO1         DOUBLE PRECISION,
       VA_CONTR_PREVIDENCIARIA1 DOUBLE PRECISION,
       VA_IMPOSTO_RENDA1    DOUBLE PRECISION,
       VA_DESC_PENSAO_ALIMENTICIA1 DOUBLE PRECISION,
       VA_SALBRUTO2         DOUBLE PRECISION,
       VA_CONTR_PREVIDENCIARIA2 DOUBLE PRECISION,
       VA_IMPOSTO_RENDA2    DOUBLE PRECISION,
       VA_DESC_PENSAO_ALIMENTICIA2 DOUBLE PRECISION,
       VA_SALBRUTO3         DOUBLE PRECISION,
       VA_CONTR_PREVIDENCIARIA3 DOUBLE PRECISION,
       VA_IMPOSTO_RENDA3    DOUBLE PRECISION,
       VA_DESC_PENSAO_ALIMENTICIA3 DOUBLE PRECISION,
       MEDIA_LIQUIDA        DOUBLE PRECISION,
       NO_PROFISSAO_SEGURADO VARCHAR(40),
       NU_PISPASEP_SEGURADO CHAR(15),
       VA_AVALIACAO_IMOVEL  DOUBLE PRECISION,
       VA_COMPRA_VENDA_IMOVEL DOUBLE PRECISION,
       IN_TEM_RENDA         CHAR(1) DEFAULT 'S',
       IN_VAI_UTILIZAR_FGTS CHAR(1) DEFAULT 'S',
       DT_ASSINATURA_DAMP   TIMESTAMP,
       DT_PAGAMENTO_RECURSOS_PROPRIOS TIMESTAMP,
       IN_DAMP1_IMOVEL_NOVO CHAR(1) DEFAULT 'N',
       NU_PESSOA            CHAR(2) NOT NULL,
       NO_SEGURADO          VARCHAR(40),
       NU_CPF_SEGURADO      VARCHAR(14),
       NO_COMPLEMENTO_SEGURADO VARCHAR(15),
       VA_AMORTIZACAO_PARCIAL DOUBLE PRECISION,
       IN_QUITA_ATRASO      CHAR(1) DEFAULT 'N',
       VA_TOTAL_ATRASO      DOUBLE PRECISION,
       NU_PREST_ATRASO1     INTEGER,
       NU_PREST_ATRASO2     INTEGER,
       NU_PREST_ATRASO3     INTEGER,
       PE_ISEN_MORA         DOUBLE PRECISION DEFAULT 0,
       PE_ISEN_CORR         DOUBLE PRECISION DEFAULT 0,
       PE_ISEN_MULTA        DOUBLE PRECISION DEFAULT 0);
CREATE INDEX XIF281FGTS_ATENDIMENTO ON FGTS_ATENDIMENTO(
       NU_ATENDIMENTO);
ALTER TABLE FGTS_ATENDIMENTO ADD CONSTRAINT XPKFGTS_ATENDIMENTO PRIMARY KEY (NU_ATENDIMENTO,
              NU_PESSOA);
CREATE TABLE IMPRESSO_TIPO_SERVICO (
       CO_SERVICO           CHAR(2) NOT NULL,
       CO_TIPO_SERVICO      CHAR(2) NOT NULL,
       ID_IMPRESSO          INTEGER NOT NULL,
       VERSAO               INTEGER NOT NULL,
       IN_PRINCIPAL         CHAR(1) DEFAULT 'S',
       IN_FASE_ATENDIMENTO  CHAR(1) DEFAULT 'S');
CREATE INDEX XIF284IMPRESSO_TIPO_SERVICO ON IMPRESSO_TIPO_SERVICO(
       ID_IMPRESSO);
ALTER TABLE IMPRESSO_TIPO_SERVICO ADD PRIMARY KEY (CO_SERVICO, CO_TIPO_SERVICO, ID_IMPRESSO);
