                                          NO_NOME_LOTE);
CREATE TABLE LOTE_DANIFICADO (
       NU_ATENDIMENTO       CHAR(8) NOT NULL,
       NU_CR                CHAR(4) NOT NULL,
       NU_QUADRA            CHAR(6) NOT NULL,
       NU_LOTE              CHAR(4) NOT NULL,
       CO_TIPO_SINISTRO     CHAR(2),
       NU_CONTRATO_MUTUARIO CHAR(17),
       IN_PERDA_CONTEUDO    CHAR(1) DEFAULT 'N',
       TE_DESCRICAO_AVARIAS BYTEA,
       IN_SERVICO_SEGURADORA CHAR(1) DEFAULT 'N',
       NU_QUITACAO_ATA      CHAR(8),
       DT_QUITACAO_ATA      TIMESTAMP,
       TE_APROVACAO_QUITACAO_ATA BYTEA,
       IN_TIPO_RESPOSTA_SEGURADORA CHAR(1),
       TE_DESCRICAO_NEGATIVA BYTEA,
       IN_TNC_ENGENHARIA    CHAR(1) DEFAULT 'N',
       CO_ENGENHEIRO_RESPONSAVEL VARCHAR(15),
       NO_MUTUARIO          VARCHAR(40),
       IN_CONTRATO_ATIVO    CHAR(1) DEFAULT 'S',
       DT_REGISTRO_QUITACAO_ATA TIMESTAMP,
       IN_PERDA_IMOVEL      VARCHAR(1) DEFAULT 'N',
       VA_RECURSOS_PROPRIOS DOUBLE PRECISION,
       VA_PAGO_INDENIZACAO  DOUBLE PRECISION,
       VA_PRESTACOES_ENCARGO DOUBLE PRECISION,
       VA_PAGO_PERDA_CONTEUDO DOUBLE PRECISION DEFAULT 0,
       DT_PAGAMENTO         TIMESTAMP,
       DT_ENVIO_PREST_ENCARGO_SCCI TIMESTAMP,
       IN_MUTUARIO_REFORMOU_IMOVEL CHAR(1) DEFAULT 'N',
       VA_QUITACAO_ATA      DOUBLE PRECISION,
       TE_DESCRICAO_PRESTACOES BYTEA,
       DT_SOLICITACAO_PAGAMENTO TIMESTAMP,
       NU_SOLICITACAO_PAGAMENTO VARCHAR(15),
       CO_SEGURADORA        CHAR(4),
       DT_RIE_CONTRATO      TIMESTAMP,
       NU_BANCO_BENEFICIARIO	  SMALLINT,
       NU_AGENCIA_BENEFICIARIO	  VARCHAR(5),
       NU_CONTA_BENEFICIARIO	  VARCHAR(18),
       NU_TIPOCONTA_BENEFICIARIO  CHAR(1));
CREATE INDEX XIF286LOTE_DANIFICADO ON LOTE_DANIFICADO(
       NU_ATENDIMENTO);
ALTER TABLE LOTE_DANIFICADO ADD PRIMARY KEY (NU_ATENDIMENTO, NU_CR, NU_QUADRA, NU_LOTE);
