  CO_TIPO_PESSOA      INTEGER DEFAULT 1,
  NU_CNPJ_CPF         VARCHAR(14),
  NU_PRETENDENTE      VARCHAR(9),
  TE_OBS              BYTEA,
  DT_INCLUSAO         TIMESTAMP,
  NO_USUARIO          VARCHAR(20),
  DT_ULT_ALTER        TIMESTAMP,
  NO_USU_ALTER        VARCHAR(20),
  NU_CONTROLE         INTEGER DEFAULT 0,
  TE_ENDERECO         BYTEA,
  DT_NASC             TIMESTAMP DEFAULT NULL);
CREATE INDEX XIF159PARTES_ACAO_JURIDICO ON PARTES_ACAO_JURIDICO( NU_MUTUARIO );
ALTER TABLE PARTES_ACAO_JURIDICO ADD CONSTRAINT XPKPARTES_JURIDICO PRIMARY KEY ( CO_PARTE );
CREATE SEQUENCE SQ_GEN_PARTES_ACAO_JURIDICO;
CREATE TABLE NATUREZA_JURIDICA (
 CO_NAT_JURIDICA         INTEGER NOT NULL,
 NO_DESC_NAT_JURIDICA    VARCHAR(15) NOT NULL);
ALTER TABLE NATUREZA_JURIDICA ADD PRIMARY KEY (CO_NAT_JURIDICA);
CREATE TABLE NATUREZA_EMPRESA (
 CO_NAT_EMPRESA         INTEGER NOT NULL,
 NO_DESC_NAT_EMPRESA    VARCHAR(15) NOT NULL);
ALTER TABLE NATUREZA_EMPRESA ADD PRIMARY KEY (CO_NAT_EMPRESA);
CREATE TABLE PADRAO_ENVIO_CORRESP (
 CO_MUNICIPIO      INTEGER NOT NULL,
 IN_USA_SEED       CHAR(1) DEFAULT 'f');
ALTER TABLE PADRAO_ENVIO_CORRESP ADD PRIMARY KEY (CO_MUNICIPIO);
CREATE TABLE PARAMETROS_MENSAGEM (
CO_PARAMETRO           INTEGER NOT NULL,
NO_EMPREENDIMENTOS     VARCHAR(50),
NO_PLANO               VARCHAR(50),
NU_DEFASAGEM           INTEGER,
CO_MENSAGEM            INTEGER,
NO_PERC_MULTA          VARCHAR(1) DEFAULT '',
MES_ANO_INICIAL        TIMESTAMP,
MES_ANO_FINAL          TIMESTAMP,
IN_TIPO_TIT            VARCHAR(15) DEFAULT '',
CO_REAJ                SMALLINT DEFAULT 0,
CO_TABGEN              SMALLINT DEFAULT 0);
ALTER TABLE PARAMETROS_MENSAGEM ADD CONSTRAINT XPKPARAMETROS_MENSAGEM PRIMARY KEY (CO_PARAMETRO);
CREATE SEQUENCE SQ_GEN_PARAM_MENSAGEM;
