CREATE TABLE VARIAVEL_TAREFA (
       NU_VARIAVEL          INTEGER NOT NULL,
       CO_VARIAVEL          VARCHAR(30),
       NO_VARIAVEL          VARCHAR(40),
       TE_VARIAVEL          BYTEA,
       IN_FORMATO_VARIAVEL  INTEGER,
       NU_TAMANHO_VARIAVEL  INTEGER,
       NU_DECIMAL_VARIAVEL  INTEGER,
       CO_ARQUIVO           VARCHAR(31),
       CO_TABELAESCOLHA           VARCHAR(50),
       CO_CAMPOTABELAESCOLHA      VARCHAR(50),
       NO_TITULOCAMPOESCOLHIDO    VARCHAR(20),
       TE_VALORVARIAVEISPOSSIVEIS BYTEA,
       CO_EMPRESA                 INTEGER DEFAULT 0);
ALTER TABLE VARIAVEL_TAREFA ADD CONSTRAINT XPKVARIAVEL_TAREFA PRIMARY KEY (NU_VARIAVEL);
CREATE TABLE VARIAVEL_TAREFA_PADRAO (
       CO_TAREFA_PADRAO     CHAR(3) NOT NULL,
       NU_VARIAVEL          INTEGER NOT NULL,
       IN_PREENCHIMENTO_OBRIGATORIO CHAR(1) DEFAULT 'N',
       IN_VISIVEL_TAREFA_SEGUINTE   CHAR(1) DEFAULT 'S',
       IN_EDITAVEL_TAREFA_SEGUINTE  CHAR(1) DEFAULT 'N');
ALTER TABLE VARIAVEL_TAREFA_PADRAO ADD CONSTRAINT PKVARIAVEL_TAREFA_PADRAO PRIMARY KEY (
              CO_TAREFA_PADRAO, NU_VARIAVEL);
ALTER TABLE VARIAVEL_TAREFA_PADRAO ADD CONSTRAINT R_TAREFA_PADRAO__VARIAVEL
              FOREIGN KEY (CO_TAREFA_PADRAO)
                             REFERENCES TAREFA_PADRAO ON DELETE CASCADE;
CREATE INDEX R_TAREFA_PADRAO__VARIAVEL ON VARIAVEL_TAREFA_PADRAO(CO_TAREFA_PADRAO);
ALTER TABLE VARIAVEL_TAREFA_PADRAO ADD CONSTRAINT R_VAR_TAREFA_VAR_TAREFA_PADRAO
              FOREIGN KEY (NU_VARIAVEL)
                             REFERENCES VARIAVEL_TAREFA;
CREATE INDEX R_VAR_TAREFA_VAR_TAREFA_PADRAO ON VARIAVEL_TAREFA_PADRAO(NU_VARIAVEL);
CREATE SEQUENCE SQ_GEN_VARIAVEL_TAREFA_PADRAO;
