CREATE TABLE AGENDAMENTO_VISTORIA (
       CO_EMPREENDIMENTO    INTEGER NOT NULL,
       NU_CONTRATO          CHAR(17) NOT NULL,
       DT_VISITACAO         TIMESTAMP NOT NULL,
       IN_STATUS_VISTORIA   CHAR(1) NOT NULL,
       DT_CADASTRAMENTO     TIMESTAMP NOT NULL);
ALTER TABLE AGENDAMENTO_VISTORIA ADD CONSTRAINT XPKAGENDAMENTO_VISTORIA PRIMARY KEY (
              CO_EMPREENDIMENTO, NU_CONTRATO, DT_VISITACAO, DT_CADASTRAMENTO);
CREATE TABLE DADOS_HISTORICO_COBRANCA(
  ID_HIST         INTEGER NOT NULL,
  NU_CONTRATO     VARCHAR(17) NOT NULL,
  DT_NOTIFICACAO  TIMESTAMP NOT NULL,
  DT_RETORNO      TIMESTAMP,
  DT_CONTATO      TIMESTAMP,
  NO_TIPO_IMOVEL  VARCHAR(30),
  NO_MATERIAL_UTILIZADO VARCHAR(30),
  NO_SITUACAO_OBRA VARCHAR(30),
  NO_TIPO_CONTRATO VARCHAR(30),
  NO_ATENDENTE_CONTATO  VARCHAR(30),
  TE_HISTORICO     BYTEA,
  CO_USUARIO       VARCHAR(50),
  CO_SETOR         VARCHAR(50));
CREATE SEQUENCE SQ_GEN_HIST_COBRANCA;
ALTER TABLE DADOS_HISTORICO_COBRANCA ADD CONSTRAINT XPKDADOS_HISTORICO_COBRANCA PRIMARY KEY (
          ID_HIST, NU_CONTRATO,DT_NOTIFICACAO);
CREATE TABLE HISTORICO_TEXTO_OCORRENCIA (
       NU_OCORRENCIA        INTEGER NOT NULL,
       DT_ALTERACAO         TIMESTAMP NOT NULL,
       CO_USUARIO_ALTERACAO CHAR(20),
       TE_TEXTO             BYTEA);
ALTER TABLE HISTORICO_TEXTO_OCORRENCIA ADD CONSTRAINT XPKHISTORICO_TEXTO_OCORRENCIA PRIMARY KEY (
              NU_OCORRENCIA, DT_ALTERACAO);
ALTER TABLE HISTORICO_TEXTO_OCORRENCIA ADD CONSTRAINT R_OCORRENCIA_SISAT__HISTORICO
              FOREIGN KEY (NU_OCORRENCIA)
              REFERENCES OCORRENCIA_SISAT ON DELETE CASCADE;
CREATE INDEX R_OCORRENCIA_SISAT__HISTORICO ON HISTORICO_TEXTO_OCORRENCIA(NU_OCORRENCIA);
CREATE TABLE DADOS_INTERFACES_BANCOS (
        NU_SEQ                  INTEGER DEFAULT 0 NOT NULL,
        CO_AGENCIA              VARCHAR(7),
        CO_SISTEMA_ORIGEM       VARCHAR(2),
        SIGLA_SISTEMA_ORIGEM    VARCHAR(2),
        POSTO_DE_SERVICO        VARCHAR(3),
        GERENTE                 VARCHAR(5),
        PROFISSAO               VARCHAR(5),
        INDICE_CORRECAO         VARCHAR(3),
        PORTARIA                VARCHAR(25),
        DT_REMESSA              TIMESTAMP);
ALTER TABLE DADOS_INTERFACES_BANCOS ADD CONSTRAINT XPKDADOS_INTERFACES_BANCOS PRIMARY KEY (NU_SEQ);
CREATE SEQUENCE SQ_GEN_DADOS_INTERFACES_BANCOS;
CREATE TABLE CODIGOS_OPERACOES (
  CO_OPERACAO              VARCHAR(7) NOT NULL,
  NO_DESCRICAO             VARCHAR(30),
  CO_CONTA                 SMALLINT,
  CO_TIPO_OPERACAO         SMALLINT,
  CO_USUARIO_RESPONSAVEL_OPER VARCHAR(20),
  NU_DIA_VENC_OPER            INTEGER);
CREATE INDEX INDICE_CODIGO_OPERACOES_01 ON CODIGOS_OPERACOES( CO_CONTA );
ALTER TABLE CODIGOS_OPERACOES ADD PRIMARY KEY (CO_OPERACAO);
ALTER TABLE CODIGOS_OPERACOES ADD CONSTRAINT R_USUARIO_RESP__CODIGOS_OPER
              FOREIGN KEY (CO_USUARIO_RESPONSAVEL_OPER)
                             REFERENCES USUARIO
                             ON DELETE SET NULL;
CREATE INDEX R_USUARIO_RESP__CODIGOS_OPER ON CODIGOS_OPERACOES(CO_USUARIO_RESPONSAVEL_OPER);
CREATE TABLE TAXAS_OPERACOES (
  CO_OPERACAO           VARCHAR(7),
  CO_TAXA               INTEGER NOT NULL,
  CO_TIPO_TAXA          SMALLINT,
  NU_PERIODICIDADE      SMALLINT,
  NU_PERIODO            SMALLINT,
  VA_TAXA               FLOAT,
  DT_REF                TIMESTAMP,
  DT_VENC_INICIAL       TIMESTAMP,
  CO_REAJ               SMALLINT,
  NU_DEFASAGEM_REAJ     SMALLINT);
ALTER TABLE TAXAS_OPERACOES ADD PRIMARY KEY (CO_TAXA);
ALTER TABLE TAXAS_OPERACOES ADD CONSTRAINT R_TAXAS_OPERACOES_CO_OPERACAO
              FOREIGN KEY (CO_OPERACAO)
                             REFERENCES CODIGOS_OPERACOES ON DELETE CASCADE;
CREATE INDEX R_TAXAS_OPERACOES_CO_OPERACAO ON TAXAS_OPERACOES(CO_OPERACAO);
CREATE SEQUENCE SQ_GEN_TAXAS_OPERACOES;
CREATE TABLE TAXAS_PRATICADAS (
  DT_INI_VIGENCIA    TIMESTAMP NOT NULL,
  DT_FIM_VIGENCIA    TIMESTAMP,
  VA_TAXA_MIN        DOUBLE PRECISION,
  VA_TAXA_MAX        DOUBLE PRECISION);
ALTER TABLE TAXAS_PRATICADAS ADD PRIMARY KEY (DT_INI_VIGENCIA);
CREATE TABLE TAB_END_RASTREABILIDADE(
  NU_SEQ        INTEGER DEFAULT 0 NOT NULL,
  NO_NOME       VARCHAR(40),
  NO_ENDE       VARCHAR(40),
  NO_COMP       VARCHAR(20),
  NO_BAIRRO     VARCHAR(20),
  NO_CIDADE     VARCHAR(20),
  CO_UF         VARCHAR(02),
  NU_CEP        VARCHAR(09));
ALTER TABLE TAB_END_RASTREABILIDADE ADD CONSTRAINT XPKTAB_END_RASTREABILIDADE PRIMARY KEY (NU_SEQ);
CREATE SEQUENCE SQ_GEN_TAB_END_RASTREABILIDADE;
CREATE TABLE HIST_COMENT (
  CO_COMENT_USUARIO        INTEGER NOT NULL,
  CO_HISTORICO_SCCI        INTEGER,
  NO_COMENT_USUARIO        VARCHAR(30));
ALTER TABLE HIST_COMENT ADD PRIMARY KEY (CO_COMENT_USUARIO);
CREATE SEQUENCE SQ_GEN_HIST_COMENT;
CREATE INDEX IDX_HIST_COMENT ON HIST_COMENT(CO_HISTORICO_SCCI,NO_COMENT_USUARIO);
CREATE TABLE PROG_REC_CREDITO (
       NU_MUTUARIO            VARCHAR(17) NOT NULL,
       DT_CALCULO             TIMESTAMP,
       TE_DADOS               BYTEA,
       CO_SITUACAO            INTEGER,
       DT_SITUACAO            TIMESTAMP,
       DT_ALT                 TIMESTAMP,
       NO_USUARIO_ALT         VARCHAR(20),
       DT_IMPLANTACAO         TIMESTAMP,
       NO_USUARIO_IMPLANTACAO VARCHAR(20),
       CO_MOTIVO_CANC_CALC_PRC INTEGER,
       TE_MOTIVO_CANC_CALC_PRC BYTEA);
ALTER TABLE PROG_REC_CREDITO ADD PRIMARY KEY (NU_MUTUARIO);
CREATE TABLE PROG_REC_CREDITO_IMPLANTADO (
       NU_SEQ                 INTEGER DEFAULT 0 NOT NULL,
       NU_MUTUARIO            VARCHAR(17) NOT NULL,
       DT_IMPLANTACAO         TIMESTAMP,
       DT_CALCULO             TIMESTAMP,
       TE_DADOS               BYTEA,
       NO_USUARIO_IMPLANTACAO VARCHAR(20));
CREATE INDEX XIF_PROG_REC_CRED_IMPLANT ON PROG_REC_CREDITO_IMPLANTADO(
  NU_MUTUARIO,
  DT_CALCULO,
  DT_IMPLANTACAO);
CREATE SEQUENCE SQ_GEN_PROG_REC_CRED_IMPLANT;
ALTER TABLE PROG_REC_CREDITO_IMPLANTADO ADD CONSTRAINT XPKTAB_PROG_REC_CRED_IMPLAN PRIMARY KEY (NU_SEQ);
CREATE TABLE CONFIG_PROG_REC_CRED (
  CO_ACORDO      INTEGER NOT NULL,
  CO_PADRAO_CTR  VARCHAR(11),
  NO_ACORDO VARCHAR(40),
  CO_TPSERIE_RESTO INTEGER);
ALTER TABLE CONFIG_PROG_REC_CRED ADD CONSTRAINT XPKCONFIG_PROG_REC_CRED PRIMARY KEY (CO_ACORDO);
CREATE TABLE DOC_ACORDO (
  CO_ACORDO    INTEGER NOT NULL,
  ID_DOCUMENTO INTEGER NOT NULL,
  NO_DOCUMENTO VARCHAR(150) NOT NULL,
  IN_FMH       CHAR(1));
ALTER TABLE DOC_ACORDO ADD CONSTRAINT XPKDOC_ACORDO PRIMARY KEY (CO_ACORDO,ID_DOCUMENTO);
ALTER TABLE DOC_ACORDO ADD CONSTRAINT XFKDOC_ACORDO FOREIGN KEY (CO_ACORDO) REFERENCES CONFIG_PROG_REC_CRED ON DELETE CASCADE;
CREATE INDEX XFKDOC_ACORDO ON DOC_ACORDO(CO_ACORDO);
CREATE TABLE MOT_CANC_CALCULO_PRC (
