CREATE TABLE PROCURADOR (
NO_PROCURADOR    VARCHAR(100),
CO_NACIONALIDADE INTEGER,
CO_ESTCIV        INTEGER,
NU_IDENTIDADE    VARCHAR(11),
NU_CPFCNPJ       VARCHAR(14),
NO_ENDERECO      VARCHAR(50),
NO_COMPLEMENTO   VARCHAR(15),
NO_CIDADE        VARCHAR(21),
CO_UF            VARCHAR(02),	
NU_CEP           VARCHAR(9),
NO_PROCURACAO    VARCHAR(30),
DT_LAVRATURA     TIMESTAMP,
NU_LIVRO         VARCHAR(30),
NU_FOLHA         VARCHAR(30),
NO_CARTORIO      VARCHAR(140),
NO_OUTORGANTE    VARCHAR(100),
NU_CONTRATO      VARCHAR(17) NOT NULL,
CO_CATEG         INTEGER,
CO_SUBCATEG      INTEGER,
NO_ORGAO_EMISSOR VARCHAR(10),
DT_NASCIMENTO    TIMESTAMP);
ALTER TABLE PROCURADOR ADD CONSTRAINT XPK_PROCURADOR PRIMARY KEY (NU_CONTRATO);
CREATE SEQUENCE SQ_GEN_SEQ_AG_PAG;
CREATE TABLE SEQUENCIA_AGENDA_PAGAMENTO(
   NU_AGENDAMENTO         INTEGER NOT NULL,
   NU_CONTRATO            VARCHAR(17) NOT NULL,
   TE_DADOS               BYTEA,
   TE_OBS                 BYTEA,
   DT_INC_AGENDAMENTO     TIMESTAMP,
   CO_USUARIO_INC         VARCHAR(20),
   DT_INI_ATRASO          TIMESTAMP,
   DT_FIM_ATRASO          TIMESTAMP,
   NU_PREST_ATRASO        INTEGER,
   VAL_ATRASO             FLOAT,
   NU_PRAZO_PARCELAMENTO  INTEGER,
   DT_PRIMEIRO_VENCIMENTO TIMESTAMP,
   NU_PREST_MENSAIS       INTEGER,
   CO_STATUS              INTEGER DEFAULT 0);
ALTER TABLE SEQUENCIA_AGENDA_PAGAMENTO ADD CONSTRAINT XPKSEQUENCIA_AGENDA_PAGAMENTO PRIMARY KEY (NU_AGENDAMENTO);
CREATE INDEX XIFSEQAGPAGCONTRATO ON SEQUENCIA_AGENDA_PAGAMENTO(NU_CONTRATO);
CREATE TABLE AGENDA_PAGAMENTO(
   NU_CONTRATO     VARCHAR(17) NOT NULL,
   CO_SERIE        INTEGER NOT NULL,
   NU_TP_PARCELA   INTEGER NOT NULL,
   NU_PARCELA      INTEGER NOT NULL,
   NU_MAC          INTEGER NOT NULL,
   DT_AGENDAMENTO  TIMESTAMP NOT NULL,
   IN_EMITIDO      CHAR(1) DEFAULT 'f',
   DT_INC_AGENDAMENTO TIMESTAMP,
   CO_USUARIO_INC  VARCHAR(20),
   PERCDESCMORA            DOUBLE PRECISION DEFAULT 0,
   PERCDESCCORR            DOUBLE PRECISION DEFAULT 0,
   PERCDESCMULTA           DOUBLE PRECISION DEFAULT 0,
   PERCDESCJREMUNERATORIOS DOUBLE PRECISION DEFAULT 0,
   CO_TIPO_AGENDAMENTO     SMALLINT DEFAULT 0,
   VA_PGTO_PARCIAL         DOUBLE PRECISION DEFAULT 0);
ALTER TABLE AGENDA_PAGAMENTO ADD CONSTRAINT XPKAGENDA_PAGAMENTO PRIMARY KEY (NU_CONTRATO,CO_SERIE,NU_TP_PARCELA,NU_PARCELA,NU_MAC);
CREATE TABLE DIFERENCA_REIMPLANTACAO(
  NU_CONTRATO           VARCHAR(17) NOT NULL,
  CO_SERIE              INTEGER NOT NULL,
  NU_OCORRENCIA         VARCHAR(9) NOT NULL,
  CO_SEQUENCIAL         INTEGER NOT NULL,
  DT_IMPLANTACAO        TIMESTAMP,
  VA_UPFATUAL           FLOAT,
  VA_UPFVENC            FLOAT,
  MAC                   SMALLINT NOT NULL,
  DIA_VENC              SMALLINT,
  CO_PEND               INTEGER,
  TP_PENDMANPARC        SMALLINT,
  DT_CONTAB             TIMESTAMP,
  DT_PAG                TIMESTAMP,
  VA_AMORT_ANT          FLOAT,
  VA_JURO_ANT           FLOAT,
  VA_SEGCRE_ANT         FLOAT,
  VA_SEGFIN_ANT         FLOAT,
  VA_SEGIMV_ANT         FLOAT,
  VA_VALTXADM_ANT       FLOAT,
  VA_TAC_ANT            FLOAT,
  VA_FCVS_ANT           FLOAT,
  VA_FGTS_ANT           FLOAT,
  VA_DESC_ANT           FLOAT,
  VA_TOTPREST_ANT       FLOAT,
  VA_AMORT_ATU          FLOAT,
  VA_JURO_ATU           FLOAT,
  VA_SEGCRE_ATU         FLOAT,
  VA_SEGFIN_ATU         FLOAT,
  VA_SEGIMV_ATU         FLOAT,
  VA_VALTXADM_ATU       FLOAT,
  VA_TAC_ATU            FLOAT,
  VA_FCVS_ATU           FLOAT,
  VA_FGTS_ATU           FLOAT,
  VA_DESC_ATU           FLOAT,
  VA_TOTPREST_ATU       FLOAT,
  VA_MORA_AMAISJ        FLOAT,
