CREATE TABLE TAB_SEQ_CR(
        CO_INTERFACE    INTEGER NOT NULL,
        DT_GERACAO      TIMESTAMP NOT NULL,
        NO_INTERFACE    VARCHAR(31) DEFAULT '',
        NU_SEQUENCIA    INTEGER DEFAULT 0);
ALTER TABLE TAB_SEQ_CR ADD CONSTRAINT XPKTAB_SEQ_CR PRIMARY KEY (CO_INTERFACE, DT_GERACAO);
CREATE SEQUENCE SQ_GEN_TAB_SEQ_CR;
CREATE TABLE VAL_PENDENTES(
        CO_SEQ_VAL_PENDENTES    INTEGER DEFAULT 0 NOT NULL,
	NU_CONTRATO		VARCHAR(17) DEFAULT '' NOT NULL,
	TP_EVENTO		SMALLINT DEFAULT 0 NOT NULL,
	DT_EVENTO    		TIMESTAMP,
	DT_INCLUSAO		TIMESTAMP,
	VA_VALOR_DEVIDO		DOUBLE PRECISION DEFAULT 0,
	CO_STATUS		SMALLINT DEFAULT 0,
	DT_STATUS		TIMESTAMP,
        NO_USUARIO		VARCHAR(21) DEFAULT '');
ALTER TABLE VAL_PENDENTES ADD CONSTRAINT XPKVAL_PENDENTES PRIMARY KEY (NU_CONTRATO,TP_EVENTO,CO_SEQ_VAL_PENDENTES);
CREATE INDEX XPLVAL_PENDENTES ON VAL_PENDENTES(CO_SEQ_VAL_PENDENTES);
CREATE SEQUENCE SQ_GEN_VAL_PENDENTES;
CREATE TABLE OCORR_VAL_PENDENTES(
        CO_OCORR_SEQ_VAL_PEND   INTEGER DEFAULT 0 NOT NULL,
        CO_SEQ_VAL_PENDENTES    INTEGER DEFAULT 0 NOT NULL,
	NU_CONTRATO		VARCHAR(17) DEFAULT '',
	MAC_PROC		SMALLINT DEFAULT 0,
	DIA_PROC		SMALLINT DEFAULT 0,
	DT_INCLUSAO		TIMESTAMP,
	DT_PAGAMENTO		TIMESTAMP,
	VA_VALOR_PAGO		DOUBLE PRECISION DEFAULT 0,
        NO_USUARIO		VARCHAR(21) DEFAULT '');
ALTER TABLE OCORR_VAL_PENDENTES ADD CONSTRAINT XPKOCORR_VAL_PENDENTES PRIMARY KEY (CO_SEQ_VAL_PENDENTES,CO_OCORR_SEQ_VAL_PEND);
CREATE INDEX XPLOCORR_VAL_PENDENTES ON OCORR_VAL_PENDENTES(MAC_PROC,DIA_PROC,NU_CONTRATO);
CREATE SEQUENCE SQ_GEN_OCORR_VAL_PENDENTES;
CREATE TABLE PENDENCIA_CONS(
       NU_CTR               VARCHAR(17) DEFAULT '' NOT NULL,
       CO_SEQ_PEND_CONS     INTEGER NOT NULL,
       CO_SEQ               INTEGER NOT NULL,
       MAC_PROC             SMALLINT NOT NULL,
       DIA_PROC             SMALLINT NOT NULL,
       DT_INCLUSAO          TIMESTAMP NOT NULL,
