CREATE /* Indica se o mutuário é politicamente exposto */ TABLE ARQCADA(
    CO_CONTRATO     	VARCHAR(17) NOT NULL,	        	/* Nş contrato Prognum */
    NU_MAC 		SMALLINT NOT NULL,			/* MAC da prestaçăo */
    NU_MATRICULA 	VARCHAR(7) 		DEFAULT '',	/* Nş da matricula c/dígito verificador do associado */
    CO_CARGO 		VARCHAR(7) 		DEFAULT '',	/* Código do cargo */
    CO_ATS 		INTEGER 		DEFAULT 0,	/* Código ATS (Adicional por tempo de serviço) */
    VA_SAL_BASE 	DOUBLE PRECISION 	DEFAULT 0,	/* Valor do salário base*/
    VA_SAL_PARTIC 	DOUBLE PRECISION	DEFAULT 0,	/* Valor do salário participaçăo */
    PE_COMPR 		DOUBLE PRECISION 	DEFAULT 0,      /* Percentual de comprometimento */
    VA_PREST_MAXIMA     DOUBLE PRECISION 	DEFAULT 0,      /* Valor da prestaçăo máxima */
    VA_PREST_IDEAL 	DOUBLE PRECISION 	DEFAULT 0,      /* Valor da prestaçăo ideal */
    VA_INDICE_IDEAL 	DOUBLE PRECISION 	DEFAULT 0,      /* Índice ideal */
    VA_TAXA_DESC 	DOUBLE PRECISION 	DEFAULT 0,      /* Valor da taxa de desconto */
    PE_BENEFICIO 	DOUBLE PRECISION 	DEFAULT 0,      /* Percentual do benefício */
    PE_PENSAO 	        DOUBLE PRECISION 	DEFAULT 0,      /* Percentual de pensăo */
    CO_CENTRO_ADM 	INTEGER 		DEFAULT 0,      /* Código do centro administrativo */
    CO_SUREG 		INTEGER 		DEFAULT 0,      /* Código SUREG */
    CO_LOTACAO 	        INTEGER 		DEFAULT 0,      /* Código unidade está lotado ou recebe pensăo */
    CO_SITUACAO 	INTEGER 		DEFAULT 0,      /* Código da situaçăo do associado */
    NU_AGENCIA_DEP 	INTEGER 		DEFAULT 0,      /* Número da agęncia empregado/aposentado/pensionista recebe pagamento/benefício */
    CO_OPERACAO 	INTEGER 		DEFAULT 0,      /* Código da operaçăo empregado/aposentado/pensionista recebe pagamento/benefício */
    NU_CONTA_DEP 	VARCHAR(11) 		DEFAULT '',      /* Número da conta empregado/aposentado/pensionista recebe pagamento/benefício */
    IN_RELAC_EMPREG     INTEGER 		DEFAULT 0,      /* Indica o tipo de afastamento do funcionário */
    VA_RENDA_GLOBAL     DOUBLE PRECISION 	DEFAULT 0,      /* Valor da renda global */
    IN_PPE 		CHAR(1));
ALTER TABLE ARQCADA ADD PRIMARY KEY (CO_CONTRATO, NU_MAC);
