CREATE TABLE RPS (
MAC                       INTEGER NOT NULL,             /* Mes ano do RPS */
CO_TIPO                   SMALLINT NOT NULL,            /* (1=SCCI, 2=Retorno FCVS, 3=Imóvel, 4=Carta de Crédito... */
CO_ID                     VARCHAR(16) NOT NULL,         /* Codigo do contrato, imóvel, cri, etc */
CO_SERIE                  INTEGER DEFAULT 0 NOT NULL,   /* Código da série de financiamento */
NO_ID                     VARCHAR(31),                  /* Nome do mutuário */
CO_SEGURADORA             INTEGER DEFAULT 0,            /* Código da Seguradora */
CO_CONTASD                INTEGER DEFAULT 0,            /* Código da conta classificada de saldo devedor*/
CO_CONTAER                INTEGER DEFAULT 0,            /* Código da conta classificada de encargos a receber */
IN_TIPO_CTA               CHAR(1) DEFAULT 'A',          /* Tipo da conta contábil - S (sintética) A (analítica) */
NU_NIVEL_CTA              SMALLINT    DEFAULT 0,            /* Nivel da conta do registro */
NU_CTA                    VARCHAR(15) DEFAULT '',       /* No. da contaSD na tabcta  */
CO_CONTA                  INTEGER DEFAULT 0,            /* Código da conta para classificaçăo */
CO_ENTIDADE               INTEGER DEFAULT 0,            /* Código da entidade detentora do crédito */
CO_CAUCAO                 INTEGER DEFAULT 0,            /* Código da entidade a qual o crédito está caucionado */
CO_REGIAO                 INTEGER DEFAULT 0,            /* Código da filial/regiao */
CO_PLANO                  INTEGER DEFAULT 0,            /* Código do plano do contrato */
CO_PA                     INTEGER DEFAULT 0,            /* Código da PA do contrato */
CO_EMPREENDIMENTO         INTEGER DEFAULT 0,            /* Código do empreendimento do contrato ou imóvel */
CO_FCVSCOBRE              CHAR(1) DEFAULT 0,            /* T se o crédito tem cobertura do fcvs, F se năo tem */
CO_CARTEIRA               INTEGER DEFAULT 0,            /* Código da carteira */
CO_SUSP                   INTEGER DEFAULT 0,            /* Código de suspensăo do contrato */
