CREATE UNIQUE INDEX CONFIG_PREJUIZO_RES4966X01 ON CONFIG_PREJUIZO_RES4966(CO_EMPRESA, CO_CARTEIRA, DT_INI_VALIDADE);
CREATE TABLE FILA_PAGAMENTOS (
    NU_SEQ            INTEGER NOT NULL,
    CO_NOSSONUM       VARCHAR(15),
    DT_PAGAMENTO      TIMESTAMP,
    VA_BAIXAOPER      DOUBLE PRECISION,
    DT_PROC           TIMESTAMP);
ALTER TABLE FILA_PAGAMENTOS ADD CONSTRAINT XPKFILA_PAGAMENTOS PRIMARY KEY (NU_SEQ);
CREATE SEQUENCE SQ_GEN_FILA_PAGAMENTOS;
CREATE TABLE TABMOTIVO_EMPRESTIMO (
  CO_MOTIVO_EMPRESTIMO        INTEGER NOT NULL,
  NO_MOTIVO_EMPRESTIMO        VARCHAR(120),
  CO_EMPRESA                  INTEGER DEFAULT 0,
  IN_TEM_OBS                  CHAR(1) DEFAULT 'f');
ALTER TABLE TABMOTIVO_EMPRESTIMO ADD CONSTRAINT XPKTABMOTIVO_EMPRESTIMO PRIMARY KEY (CO_MOTIVO_EMPRESTIMO);
CREATE TABLE MOTIVO_EMPRESTIMO (
  NU_OPERACAO           INTEGER NOT NULL,
  CO_MOTIVO_EMPRESTIMO  INTEGER NOT NULL,
  NO_OBSERVACAO         VARCHAR(150));
ALTER TABLE MOTIVO_EMPRESTIMO ADD CONSTRAINT XPKMOTIVO_EMPRESTIMO PRIMARY KEY (NU_OPERACAO,CO_MOTIVO_EMPRESTIMO);
ALTER TABLE MOTIVO_EMPRESTIMO ADD CONSTRAINT XFK1_MOTIVO_EMPRESTIMO
  FOREIGN KEY (NU_OPERACAO) REFERENCES OPERACAO_CREDITO;
CREATE INDEX XFK1_MOTIVO_EMPRESTIMO ON MOTIVO_EMPRESTIMO(NU_OPERACAO);
ALTER TABLE MOTIVO_EMPRESTIMO ADD CONSTRAINT XFK2_MOTIVO_EMPRESTIMO
  FOREIGN KEY (CO_MOTIVO_EMPRESTIMO) REFERENCES TABMOTIVO_EMPRESTIMO;
CREATE INDEX XFK2_MOTIVO_EMPRESTIMO ON MOTIVO_EMPRESTIMO(CO_MOTIVO_EMPRESTIMO);
CREATE TABLE CONFIG_CURA_AP (
  NU_SEQ                  INTEGER NOT NULL,
  CO_EMPRESA              INTEGER NOT NULL,
  CO_CARTEIRA             INTEGER NOT NULL,
  CO_MOTIVO_CONTAMINACAO  SMALLINT NOT NULL,
  DT_INI_VALIDADE         TIMESTAMP NOT NULL,
  DT_FIM_VALIDADE         TIMESTAMP,
  NU_PER_ADIMPLENTE       SMALLINT,
  CO_MOTIVO_CURA          SMALLINT,
  NU_DIAS_MARGE_ATRASO    SMALLINT);
CREATE SEQUENCE SQ_GEN_CONFIG_CURA_AP;
ALTER TABLE CONFIG_CURA_AP ADD CONSTRAINT XPKCONFIG_CURA_AP PRIMARY KEY (NU_SEQ);
CREATE UNIQUE INDEX CONFIG_CURA_APX01 ON CONFIG_CURA_AP(CO_MOTIVO_CONTAMINACAO,CO_EMPRESA,CO_CARTEIRA,DT_INI_VALIDADE);
CREATE TABLE PASTA_DOCUMENTOS (
  NU_PASTA          INTEGER NOT NULL,
  NU_DOCUMENTO      INTEGER NOT NULL,
  NU_OPERACAO       INTEGER NOT NULL,
  NU_OCORRENCIA     INTEGER NOT NULL);
CREATE SEQUENCE SQ_GEN_PASTA_DOCUMENTOS;
ALTER TABLE PASTA_DOCUMENTOS ADD CONSTRAINT XPKPASTA_DOCUMENTOS PRIMARY KEY (NU_PASTA, NU_DOCUMENTO);
ALTER TABLE PASTA_DOCUMENTOS ADD CONSTRAINT R_OPERACAO__PASTA_DOC
              FOREIGN KEY (NU_OPERACAO)
                             REFERENCES OPERACAO_CREDITO;
CREATE INDEX R_OPERACAO__PASTA_DOC ON PASTA_DOCUMENTOS(NU_OPERACAO);
ALTER TABLE PASTA_DOCUMENTOS ADD CONSTRAINT R_OCORRENCIA__PASTA_DOC
              FOREIGN KEY (NU_OCORRENCIA)
                             REFERENCES OCORRENCIA_SISAT;
CREATE INDEX R_OCORRENCIA__PASTA_DOC ON PASTA_DOCUMENTOS(NU_OCORRENCIA);
CREATE TABLE RASTREIO_PIX_AUTOMATICO (
  CO_CONTRATO                 VARCHAR(17) NOT NULL,
  NOSSONUM                    VARCHAR(15) NOT NULL,
  DATAEMIS                    TIMESTAMP,
  DATAVENCREC                 TIMESTAMP,
  VALTIT                      DOUBLE PRECISION DEFAULT 0,
  CO_LCOBR                    INTEGER DEFAULT 0,
  TXID_PIX_AUT                VARCHAR(35),
  NU_TENTATIVAS               VARCHAR(5) DEFAULT '',
  DT_TENTATIVA                TIMESTAMP,
  TE_DESCRICAO_TRANSACAO      VARCHAR(77) DEFAULT '',
  DT_CRIACAO_RECORRENCIA      TIMESTAMP,
  STATUS                      VARCHAR(31),
  ID_REC_PIX_AUT              VARCHAR(77) DEFAULT '');
