CREATE TABLE PARCELASCTB(
  MAC                       INTEGER NOT NULL,             /* Mes ano do RPS */
  CO_TIPO                   SMALLINT NOT NULL,            /* (1=SCCI, 2=Retorno FCVS, 3=Imóvel, 4=Carta de Crédito... */
  CO_ID                     VARCHAR(16) NOT NULL,         /* Codigo do contrato, imóvel, cri, etc */
  CO_SERIE                  INTEGER DEFAULT 0 NOT NULL,   /* Código da série de financiamento */
  TE_DADOS                  BYTEA,
  DT_CTB                    TIMESTAMP,
  SITUACAO_CTB              SMALLINT DEFAULT 0,
  DTSITUACAO_CTB            TIMESTAMP);
ALTER TABLE PARCELASCTB ADD CONSTRAINT XPKPARCELASCTB
       PRIMARY KEY (MAC,CO_TIPO,CO_ID,CO_SERIE);
CREATE TABLE CRONOGRAMA_REPASSE_EMPREEND(
  EMPREEND                  INTEGER NOT NULL,
  DT_PREVISAO_REPASSE       TIMESTAMP NOT NULL,             /* data da previsăo do repasse  */
  PE_REPASSE                DOUBLE PRECISION DEFAULT 0, /* percentual a ser repassado em Dt_Repasse */
  DT_ALTERACAO              TIMESTAMP,                      /* data do cadastramento da previsăo - DataH */
  USUARIO_ALTERACAO         VARCHAR(20) DEFAULT '');
ALTER TABLE CRONOGRAMA_REPASSE_EMPREEND ADD CONSTRAINT XPKCRONOGRAMA_REPASSE_EMPREEND
       PRIMARY KEY (EMPREEND,DT_PREVISAO_REPASSE);
CREATE TABLE ENTIDADES_PROPRIETARIOS(
  CO_ENTIDADE                   INTEGER NOT NULL,
  CO_SEQ                        INTEGER NOT NULL,
  NO_NOME                       VARCHAR(40) DEFAULT '',
  NU_CPF                        VARCHAR(14) DEFAULT '',
  NU_RG                         VARCHAR (15) DEFAULT '',
  CO_NACIONALIDADE              SMALLINT DEFAULT 0,
  CO_ESTCIVIL                   SMALLINT DEFAULT 0,
  CO_PROFISSAO	                SMALLINT DEFAULT 0,
  NO_ENDERECO                   VARCHAR (40) DEFAULT '',
  NO_BAIRRO                     VARCHAR (21) DEFAULT '',
  NO_CIDADE                     VARCHAR (40) DEFAULT '',
  CO_UF                         VARCHAR (2)  DEFAULT '',
  NU_CEP                        VARCHAR (9)  DEFAULT '',
  NU_TELEFONE                   VARCHAR (11) DEFAULT '',
  NO_EMAIL                      VARCHAR (80) DEFAULT '');
ALTER TABLE ENTIDADES_PROPRIETARIOS ADD PRIMARY KEY (CO_ENTIDADE,CO_SEQ);
CREATE SEQUENCE SQ_GEN_ENTIDADES_PROPRIETARIOS;
