       CO_APLIC             INTEGER NOT NULL,
       CO_SEVERIDADE        SMALLINT NOT NULL,
       NU_CONTRATO          VARCHAR(17),
       NO_USUARIO           VARCHAR(20),
       DT_DATA_HORA         TIMESTAMP NOT NULL,
       NO_MENSAGEM          VARCHAR(71),
       NO_COMPLEMENTO       VARCHAR(71),
       CO_DETALHE           INTEGER,
       DT_DATA_DETALHE      VARCHAR(14),
       TE_DADOS             BYTEA,
       NU_PRETENDENTE       VARCHAR(9),
       NO_TABELA            VARCHAR(40),
       NO_BASE              VARCHAR(15),
       CO_USUARIO_LEITURA   VARCHAR(20) DEFAULT '',
       DT_LEITURA           TIMESTAMP DEFAULT NULL,
       NO_USUARIO_ALTERADO  VARCHAR(20),
       CO_EMPRESA           INTEGER DEFAULT 0);
ALTER TABLE LOG_EVENTOS_EXC ADD CONSTRAINT XPKLOG_EVENTOS_EXC PRIMARY KEY (CO_LOG);
CREATE INDEX XIFLOG_EVENTOS_EXC_APLIC ON LOG_EVENTOS_EXC(CO_APLIC);
CREATE INDEX XIFLOG_EVENTOS_EXC_DETALHE ON LOG_EVENTOS_EXC(CO_APLIC,CO_DETALHE,DT_DATA_DETALHE);
CREATE INDEX XIFLOG_EVENTOS_EXC_IXD ON LOG_EVENTOS_EXC(CO_APLIC,DT_DATA_HORA);
CREATE INDEX XIFLOG_EVENTOS_EXC_IXDDB ON LOG_EVENTOS_EXC(NU_CONTRATO,DT_DATA_HORA);
CREATE INDEX XIFLOG_EVENTOS_EXC_PRETDATA ON LOG_EVENTOS_EXC(NU_PRETENDENTE,DT_DATA_HORA);
CREATE INDEX XIFLOG_EVENTOS_EXC_TABDATA ON LOG_EVENTOS_EXC(NO_TABELA,DT_DATA_HORA);
CREATE INDEX XIFLOG_EVENTOS_EXC_BASEDATA ON LOG_EVENTOS_EXC(NO_BASE,DT_DATA_HORA);
CREATE INDEX XIFLOG_EVENTOS_EXC_DATAHORA on log_eventos_EXC (dt_data_hora DESC);
CREATE INDEX XIFLOG_EVENTOS_EXC_USUARIO ON LOG_EVENTOS_EXC(NO_USUARIO, CO_APLIC, DT_DATA_HORA);
CREATE INDEX XIF_LOG_EVENTOS_EXC_CONTRATO ON LOG_EVENTOS_EXC(NU_CONTRATO);
CREATE TABLE GERENCIAMENTO_AUX (
  NU_SEQ                   INTEGER NOT NULL,
  DT_REFERENCIA            TIMESTAMP DEFAULT '1899-12-30',
  CO_CONTRATO              VARCHAR(17),
  CAD_CTRVELHO             VARCHAR(17),
  CAD_NOME                 VARCHAR(40),
  CAD_CPF                  VARCHAR(14),
  CALC_CONTABIL_STATUS     SMALLINT DEFAULT 0,
  VLRCONTBR                DOUBLE PRECISION,
  VA_SALDO_DEVEDOR_FINANC  DOUBLE PRECISION,
  VA_PRO_RATA              DOUBLE PRECISION,
  VA_SALDO_CORRIGIDO       DOUBLE PRECISION,
  VA_TAXA_JUROS            DOUBLE PRECISION,
  VA_JUROS_CONT            DOUBLE PRECISION,
  VA_SEGURO                DOUBLE PRECISION,
  VA_ABATIMENTO_FGTS       DOUBLE PRECISION,
  VA_ATRASO                DOUBLE PRECISION,
  VA_DIF_LIMINAR           DOUBLE PRECISION,
  VA_RESIDUO               DOUBLE PRECISION,
  VA_DESC_FCVS             DOUBLE PRECISION,
  VA_DESC_AGENTE           DOUBLE PRECISION,
  VA_DESC_TESOURO          DOUBLE PRECISION,
  VA_ACORDO_PENDENCIA      DOUBLE PRECISION,
  VA_SERIES_VINCENDAS      DOUBLE PRECISION,
  VA_DEVOLPRSTPAGA         DOUBLE PRECISION,
  VA_TAXAS                 DOUBLE PRECISION,
  DESC_RESTITUIDO          DOUBLE PRECISION,
  VA_QUITACAO              DOUBLE PRECISION,
  VA_FGTS_UTIL             DOUBLE PRECISION);
ALTER TABLE GERENCIAMENTO_AUX ADD CONSTRAINT XPKGERENCIAMENTO_AUX PRIMARY KEY (NU_SEQ);
CREATE SEQUENCE SQ_GEN_GERENCIAMENTO_AUX;
